"""
govor.py - Govoreshta programa ot Borislav Zahariev
=====================================================
MicroPython port for Raspberry Pi Pico / RP2040

Uses the RP2040 PIO (Programmable I/O) for cycle-exact speaker
timing — the closest you can get to the original 6502's STX $C030.

The PIO state machine runs a tiny 8-instruction program that
alternates the pin HIGH/LOW with precise cycle-counted delays.
Python just feeds delay values into the FIFO; the PIO handles
all timing deterministically, independent of the CPU.

  PIO clock: 1.023 MHz  (= Apple II CPU frequency!)
  Jitter:    0 cycles    (PIO is deterministic)
  CPU load:  near zero   (FIFO absorbs Python overhead)

Wiring:
    GPIO ---[ 100 ohm ]---( speaker+ )
                           ( speaker- )--- GND

Usage:
    >>> from govor import Govor
    >>> g = Govor(pin=15)
    >>> g.speak("zdrasti")
    >>> g.say("здрасти")
    >>> g.demo()
    >>> g.speed = 5

Original (c) Borislav Zachariev, late 1980s
"""

import rp2
from machine import Pin
import time

# ============================================================================
#  PHONEME DATA
# ============================================================================
