_W = {}
for _k, _v in _P.items():
    _W[_k] = bytes.fromhex(_v) if _v else b''
del _P

_CYR = {
    '\u0430':'a','\u0431':'b','\u0432':'v','\u0433':'g',
    '\u0434':'d','\u0435':'e','\u0436':'j','\u0437':'z',
    '\u0438':'i','\u0439':'y','\u043a':'k','\u043b':'l',
    '\u043c':'m','\u043d':'n','\u043e':'o','\u043f':'p',
    '\u0440':'r','\u0441':'s','\u0442':'t','\u0443':'u',
    '\u0444':'f','\u0445':'h','\u0446':'c','\u0447':'^',
    '\u0448':'[','\u0449':']','\u044a':'w','\u044c':'y',
    '\u044e':'`','\u044f':'q',
}

def to_govor(text):
    r = []
    for c in text.lower():
        if c in _CYR:
            r.append(_CYR[c])
        elif c in _W or c == ' ':
            r.append(c)
    return ''.join(r)


# ============================================================================
#  PIO PROGRAM — 8 instructions, cycle-exact speaker driver
# ============================================================================
#
#  The state machine alternates the output pin HIGH and LOW.
#  Each half-cycle duration is pulled from the TX FIFO as a
#  cycle count.  When the FIFO is empty, `pull(block)` stalls
#  the PIO with the pin held LOW — natural silence.
#
#  PIO clock = 1.023 MHz  →  1 PIO cycle ≈ 1 Apple II CPU cycle
#
#  Timing per half-cycle:
#    pull(block)    1 cycle   (or stalls waiting for data)
#    mov(x, osr)   1 cycle
#    set(pins, _)  1 cycle
#    delay loop     X cycles  (jmp x_dec: 1 cycle per iteration)
#                  ---------
#    Total:         X + 3 cycles overhead
#
#  For X=0: set(pins), jmp falls through → 1-cycle pulse (inaudible)

@rp2.asm_pio(set_init=rp2.PIO.OUT_LOW)
def _pio_spk():
    """PIO program: pull delay, set HIGH, count down, pull, set LOW, count down."""
    wrap_target()
    pull(block)             # stalls here when idle (pin stays LOW)
    mov(x, osr)             # X = delay cycle count
    set(pins, 1)            # pin HIGH
    label("dh")
    jmp(x_dec, "dh")        # count down (X cycles)
    pull(block)
    mov(x, osr)
    set(pins, 0)            # pin LOW
    label("dl")
    jmp(x_dec, "dl")
    wrap()


# ============================================================================
#  GOVOR CLASS
# ============================================================================

class Govor:
    """
    Speech synthesiser using RP2040 PIO for cycle-exact audio.

    The PIO state machine handles pin toggling with deterministic
    timing.  Python feeds delay values into the 8-deep TX FIFO.
    The FIFO absorbs any Python loop jitter — as long as Python
    can feed faster than the PIO consumes (easily, since each
    half-cycle is ~50-500 µs and Python can push in ~5 µs), the
    audio is perfectly clean.
    """

    def __init__(self, pin=15, speed=8, sm_id=0):
        """
        Args:
            pin:    GPIO number for speaker
            speed:  1-12 (default 8, higher = slower/deeper)
            sm_id:  PIO state machine index (0-7)
        """
        self._pin = Pin(pin, Pin.OUT, value=0)
        self._sm = rp2.StateMachine(sm_id, _pio_spk,
                                     freq=1_023_000,
                                     set_base=self._pin)
        self._speed = max(1, min(15, speed))
        self._recalc()
        self._sm.active(1)
        self._feeds = 0  # track odd/even for phase

    def _recalc(self):
        # PIO cycles per timing-value unit.
        # At 1.023 MHz PIO clock, 1 cycle = 1 Apple II CPU cycle.
        # Original delay per unit: (5*speed + 6) CPU cycles.
        # Subtract 3 for PIO overhead (pull + mov + set).
        raw = 5 * self._speed + 6
        self._cpu = max(1, raw - 3)

    @property
    def speed(self):
        return self._speed

    @speed.setter
    def speed(self, v):
        self._speed = max(1, min(15, v))
        self._recalc()

    def _put(self, cycles):
        """Push one delay value to PIO FIFO (blocks if full)."""
        self._sm.put(cycles)
        self._feeds += 1

    def _end_phoneme(self):
        """Ensure PIO ends in the LOW-wait state (pin LOW, blocking on pull)."""
        if self._feeds & 1:
            # Odd number of feeds → PIO is waiting for a LOW value.
            # Feed a minimal LOW to complete the cycle.
            self._sm.put(0)
            self._feeds += 1
        # Now PIO is blocked at wrap_target pull(block) with pin LOW.

    @micropython.native
    def _play_nibble(self, raw):
        """Feed a nibble-mode phoneme to PIO."""
        put = self._sm.put
        cpu = self._cpu
        pos = 1  # skip 0xFF prefix
        rep = raw[pos]
        if rep == 0:
            rep = 1
        pos += 1
        ws = pos
        rlen = len(raw)

        for _ in range(rep):
            p = ws
            while p < rlen:
                b = raw[p]; p += 1
                hi = (b >> 4) & 0x0F
                lo = b & 0x0F
                if b == 0:
                    # Silence: two minimal pulses (inaudible)
                    put(0)
                    put(0)
                else:
                    put(hi * cpu if hi else 0)
                    put(lo * cpu if lo else 0)
        self._feeds = 0  # nibble always feeds pairs → even

    @micropython.native
    def _play_byte(self, raw):
        """Feed a byte-mode phoneme to PIO."""
        put = self._sm.put
        cpu = self._cpu
        rep = raw[0]
        if rep == 0:
            rep = 1
        ws = 1
        rlen = len(raw)
        count = 0

        for _ in range(rep):
            p = ws
            while p < rlen:
                b = raw[p]; p += 1
                if b == 0:
                    # Silence gap: feed a pair of minimal pulses
                    put(0)
                    put(0)
                    count += 2
                else:
                    put(b * cpu)
                    count += 1

        self._feeds = count

    def phoneme(self, ch):
        """Play one phoneme."""
        if ch == ' ':
            self._end_phoneme()
            time.sleep_ms(max(5, self._speed * 3))
            return
        raw = _W.get(ch)
        if not raw or len(raw) < 2:
            return

        if raw[0] == 0xFF:
            self._play_nibble(raw)
        else:
            self._play_byte(raw)
        self._end_phoneme()

    def speak(self, text):
        """Speak Latin-transliterated text.

        >>> g.speak("zdrasti")
        >>> g.speak("gowore]a programa ot borislaw zahariew")
        """
        spd = self._speed
        for ch in text:
            if ch == '/':
                self.speed = self._speed - 1
            elif ch == ':':
                self.speed = self._speed + 1
            elif ch.isdigit():
                self.speed = int(ch) + 3
            elif ch == ' ':
                self._end_phoneme()
                time.sleep_ms(max(5, self._speed * 3))
            elif ch in _W:
                raw = _W[ch]
                if raw and len(raw) >= 2:
                    if raw[0] == 0xFF:
                        self._play_nibble(raw)
                    else:
                        self._play_byte(raw)
                    self._end_phoneme()
        self._speed = spd
        self._recalc()

    def say(self, text):
        """Speak Cyrillic text.

        >>> g.say("здрасти")
        """
        self.speak(to_govor(text))

    def demo(self):
        """The classic intro."""
        self.speak("gowore]a programa ot borislaw zahariew")

    def test(self):
        """Quick sound check: vowels + greeting."""
        for v in 'aeiou':
            self.phoneme(v)
            time.sleep_ms(30)
        time.sleep_ms(80)
        self.speak("zdrasti")

    def deinit(self):
        """Release PIO state machine."""
        self._sm.active(0)
        self._pin.value(0)
